:group --></div>\n<!-- /wp:group -->\n\n<!-- wp:columns {\"align\":\"wide\",\"style\":{\"spacing\":{\"blockGap\":{\"top\":\"4rem\",\"left\":\"4rem\"},\"padding\":{\"top\":\"0px\",\"right\":\"0px\",\"bottom\":\"0px\",\"left\":\"0px\"}}}} -->\n<div class=\"wp-block-columns alignwide\" style=\"padding-top:0px;padding-right:0px;padding-bottom:0px;padding-left:0px\"><!-- wp:column {\"verticalAlignment\":\"bottom\",\"width\":\"40em\"} -->\n<div class=\"wp-block-column is-vertically-aligned-bottom\" style=\"flex-basis:40em\"><!-- wp:heading {\"textAlign\":\"left\",\"level\":1,\"align\":\"wide\",\"style\":{\"typography\":{\"fontSize\":\"3.6rem\"}}} -->\n<h1 class=\"wp-block-heading alignwide has-text-align-left\" style=\"font-size:3.6rem\">Welcome to the StartOrg Foundation.</h1>\n<!-- /wp:heading -->\n\n<!-- wp:group {\"style\":{\"spacing\":{\"blockGap\":\"2.4rem\"}},\"layout\":{\"type\":\"flex\",\"orientation\":\"vertical\",\"justifyContent\":\"left\",\"flexWrap\":\"wrap\"}} -->\n<div class=\"wp-block-group\"><!-- wp:paragraph {\"align\":\"left\"} -->\n<p class=\"has-text-align-left\">We\'re a non-profit organization made up of more than 30 entities working in education, research, and community development.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:buttons -->\n<div class=\"wp-block-buttons\"><!-- wp:button {\"className\":\"is-style-outline\"} -->\n<div class=\"wp-block-button is-style-outline\"><a class=\"wp-block-button__link wp-element-button\">Learn More</a></div>\n<!-- /wp:button --></div>\n<!-- /wp:buttons --></div>\n<!-- /wp:group -->\n\n<!-- wp:spacer -->\n<div style=\"height:100px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n<!-- /wp:spacer --></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns --></div>\n<!-- /wp:group --></div></div>\n<!-- /wp:cover -->','Header','','inherit','closed','closed','','18-revision-v1','','','2025-09-09 22:05:52','2025-09-09 22:05:52','',18,'http://starsforeurope.local/?p=19',0,'revision','',0),(20,1,'2025-09-09 22:09:02','2