-font-size\">Learn about our new research initiatives</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"align\":\"left\"} -->\n<p class=\"has-text-align-left\">Research is the backbone of innovation. At StartOrg Foundation we are committed to pushing the boundaries of knowledge.</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:group --></div>\n<!-- /wp:column -->\n\n<!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:group {\"style\":{\"spacing\":{\"blockGap\":\"1.2rem\"}},\"layout\":{\"type\":\"flex\",\"orientation\":\"vertical\",\"justifyContent\":\"stretch\"}} -->\n<div class=\"wp-block-group\"><!-- wp:image {\"sizeSlug\":\"full\",\"linkDestination\":\"none\",\"style\":{\"border\":{\"top\":{\"color\":\"var:preset|color|secondary\",\"width\":\"2px\"},\"right\":[],\"bottom\":[],\"left\":[]}}} -->\n<figure class=\"wp-block-image size-full has-custom-border\"><img src=\"http://starsforeurope.local/wp-content/themes/startorg/assets/images/home_image_5.jpg\" alt=\"\" style=\"border-top-color:var(--wp--preset--color--secondary);border-top-width:2px\"/></figure>\n<!-- /wp:image -->\n\n<!-- wp:heading {\"textAlign\":\"left\",\"level\":3,\"fontSize\":\"large\"} -->\n<h3 class=\"wp-block-heading has-text-align-left has-large-font-size\">Explore our development programs</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"align\":\"left\"} -->\n<p class=\"has-text-align-left\">Beyond the confines of traditional academia, our organization is deeply rooted in community development.</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:group --></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns --></div>\n<!-- /wp:group -->\n\n<!-- wp:cover {\"url\":\"http://starsforeurope.local/wp-content/uploads/2025/09/Progetto-senza-titolo-1024x683.jpg\",\"id\":35,\"dimRatio\":70,\"overlayColor\":\"tertiary\",\"isUserOverlayColor\":true,\"minHeight\":590,\"minHeightUnit\":\"px\",\"sizeSlug\":\"large\",\"style\":{\"spacing\":{\"padding\":{\"top\":\"0px\",\"right\":\"4vw\",\"bottom\":\"0px\",\"left\"