    width: 100%;\n    padding: 14px;\n    border: none;\n    border-radius: 10px;\n    background: linear-gradient(135deg, #0073aa, #0099cc);\n    color: #fff;\n    font-size: 16px;\n    font-weight: bold;\n    cursor: pointer;\n    transition: transform 0.2s ease, box-shadow 0.2s ease;\n  }\n\n  .contact-form button:hover {\n    transform: translateY(-2px);\n    box-shadow: 0 6px 15px rgba(0,115,170,0.3);\n  }\n\n  /* Responsive */\n  @media (max-width: 600px) {\n    .contact-form {\n      padding: 20px;\n    }\n    .contact-form h2 {\n      font-size: 20px;\n    }\n  }\n</style>\n\n<form class=\"contact-form\" \n      action=\"mailto:tuoindirizzo@email.com\" \n      method=\"post\" \n      enctype=\"text/plain\">\n  <h2>Contattaci</h2>\n\n  <div class=\"form-group\">\n    <label for=\"nome\">Nome*</label>\n    <input type=\"text\" id=\"nome\" name=\"nome\" required>\n  </div>\n\n  <div class=\"form-group\">\n    <label for=\"email\">Email*</label>\n    <input type=\"email\" id=\"email\" name=\"email\" required>\n  </div>\n\n  <div class=\"form-group\">\n    <label for=\"messaggio\">Messaggio*</label>\n    <textarea id=\"messaggio\" name=\"messaggio\" required></textarea>\n  </div>\n\n  <button type=\"submit\">Invia Messaggio</button>\n</form>\n\n<!-- /wp:html --></div>\n<!-- /wp:group --></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns --></div>\n<!-- /wp:group -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator --></main>\n<!-- /wp:group -->\n\n<!-- wp:template-part {\"slug\":\"footer\",\"theme\":\"startorg\",\"tagName\":\"footer\",\"area\":\"footer\"} /--></div>\n<!-- /wp:group -->','Home del blog','Visualizza gli ultimi articoli come homepage del sito o come \"Pagina degli articoli\", come definito nelle impostazioni di lettura. Se esiste, il template Pagina principale sovrascrive questo template quando gli articoli vengono visualizzati nella homepage.','inherit','closed','closed','','23-revision-v1'