63_1107\">Iscriviti per essere aggiornato o per chiederci informazioni</h2>\n<!-- /wp:heading --></div>\n<!-- /wp:column -->\n\n<!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:group {\"style\":{\"spacing\":{\"blockGap\":\"0px\"}},\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group\"><!-- wp:html -->\n<style>\n  .contact-form {\n    max-width: 600px;\n    margin: 30px auto;\n    padding: 30px;\n    background: #ffffff;\n    border-radius: 16px;\n    box-shadow: 0 8px 20px rgba(0,0,0,0.08);\n    font-family: \"Helvetica Neue\", Arial, sans-serif;\n  }\n\n  .contact-form h2 {\n    text-align: center;\n    margin-bottom: 20px;\n    font-size: 24px;\n    color: #0073aa;\n  }\n\n  .form-group {\n    margin-bottom: 18px;\n  }\n\n  .contact-form label {\n    display: block;\n    margin-bottom: 6px;\n    font-weight: 600;\n    color: #444;\n    font-size: 14px;\n  }\n\n  .contact-form input,\n  .contact-form textarea {\n    width: 100%;\n    padding: 14px 16px;\n    border: 1px solid #ddd;\n    border-radius: 10px;\n    font-size: 15px;\n    transition: all 0.3s ease;\n    background: #fafafa;\n  }\n\n  .contact-form input:focus,\n  .contact-form textarea:focus {\n    border-color: #0073aa;\n    background: #fff;\n    outline: none;\n    box-shadow: 0 0 6px rgba(0,115,170,0.2);\n  }\n\n  .contact-form textarea {\n    resize: vertical;\n    min-height: 120px;\n  }\n\n  .contact-form button {\n    width: 100%;\n    padding: 14px;\n    border: none;\n    border-radius: 10px;\n    background: linear-gradient(135deg, #0073aa, #0099cc);\n    color: #fff;\n    font-size: 16px;\n    font-weight: bold;\n    cursor: pointer;\n    transition: transform 0.2s ease, box-shadow 0.2s ease;\n  }\n\n  .contact-form button:hover {\n    transform: translateY(-2px);\n    box-shadow: 0 6px 15px rgba(0,115,170,0.3);\n  }\n\n  /* Responsive */\n  @media (max-width: 600px) {\n    .contact-form {\n      padding: 20px;\n    }\n    .contact-form h2 {\n      font-size: 20px;\n    }\n  }\n</style>\n\n<form class=\"contact-form\" \n      action=\"mailto:tuoindirizzo@email.com\" \n      method=\"post\" \n      enctype=\"text/plain\">\n  <h2>Contattaci</h2>\n\n  <div class=\"form-group\">\n    <label for=\"nome\">Nome*</label>\n    <input type=\"text\" id=\"nome\" name=\"nome\" required>\n  </div>\n\n  <div class=\"form-group\">\n    <label for=\"email\">Email*</label>\n    <input type=\"email\" id=\"email\" name=\"email\" required>\n  </div>\n\n  <div class=\"form-group\">\n    <label for=\"messaggio\">Messaggio*</label>\n    <textarea id=\"messaggio\" name=\"messaggio\" required></textarea>\n  </div>\n\n  <button type=\"submit\">Invia Messaggio</button>\n</form>\n<!-- /wp:html --></div>\n<!-- /wp:group --></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns --></div>\n<!-- /wp:group -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator --></main>\n<!-- /wp:group -->\n\n<!-- wp:template-part {\"slug\":\"footer\",\"theme\":\"startorg\",\"tagName\":\"footer\",\"area\":\"footer\"} /--></div>\n<!-- /wp:group -->','Home del blog','Visualizza gli ultimi articoli come homepage del sito o come \"Pagina degli articoli\", come definito nelle impostazioni di lettura. Se esiste, il template Pagina principale sovrascrive questo template quando gli articoli vengono visualizzati nella homepage.','inherit','closed','closed','','23-revision-v1','','','2025-09-10 00:14:30','2025-09-10 00:14:30','',23,'http://starsforeurope.local/?p=51',0,'revision','',0),(52,1,'2025-09-10 00:16:20','2025-09-10 00:16:20','{\"styles\":[],\"settings\":[],\"isGlobalStylesUserThemeJSON\":true,\"version\":3}','Custom Styles','','inherit','closed','closed','','7-revision-v1','','','2025-09-10 00:16:20','2025-09-10 00:16:20','',7,'http://starsforeurope.local/?p=52',0,'revision','',0),(53,1,'2025-09-10 00:20:43','2025-09-10 00:20:43','{\"styles\":{\"blocks\":{\"core\\/group\":{\"spacing\":{\"blockGap\":\"0.6rem\"}}}},\"setti