le\":{\"color\":[]}} -->\n<div class=\"wp-block-cover\"><img class=\"wp-block-cover__image-background wp-image-60\" alt=\"\" src=\"http://starsforeurope.local/wp-content/uploads/2025/09/Progetto-senza-titolo1-scaled.jpg\" data-object-fit=\"cover\"/><span aria-hidden=\"true\" class=\"wp-block-cover__background has-background-dim\"></span><div class=\"wp-block-cover__inner-container\"><!-- wp:paragraph {\"align\":\"center\",\"placeholder\":\"Scrivi il titolo...\",\"fontSize\":\"large\"} -->\n<p class=\"has-text-align-center has-large-font-size\">Sei un atleta o un ex atleta?</p>\n<!-- /wp:paragraph --></div></div>\n<!-- /wp:cover -->\n\n<!-- wp:paragraph {\"align\":\"left\",\"style\":{\"typography\":{\"fontSize\":\"1.3rem\"}}} -->\n<p class=\"has-text-align-left\" style=\"font-size:1.3rem\">Unisci a noi e diventa un nostro ambasciatore</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:group --></div>\n<!-- /wp:column -->\n\n<!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:group {\"style\":{\"spacing\":{\"blockGap\":\"1.2rem\"}},\"layout\":{\"type\":\"flex\",\"orientation\":\"vertical\",\"justifyContent\":\"stretch\"}} -->\n<div class=\"wp-block-group\"><!-- wp:cover {\"url\":\"http://starsforeurope.local/wp-content/uploads/2025/09/ittadino-scaled.jpg\",\"id\":61,\"dimRatio\":50,\"style\":{\"color\":[]}} -->\n<div class=\"wp-block-cover\"><img class=\"wp-block-cover__image-background wp-image-61\" alt=\"\" src=\"http://starsforeurope.local/wp-content/uploads/2025/09/ittadino-scaled.jpg\" data-object-fit=\"cover\"/><span aria-hidden=\"true\" class=\"wp-block-cover__background has-background-dim\"></span><div class=\"wp-block-cover__inner-container\"><!-- wp:paragraph {\"align\":\"center\",\"fontSize\":\"large\"} -->\n<p class=\"has-text-align-center has-large-font-size\">Sei un cittadino?</p>\n<!-- /wp:paragraph --></div></div>\n<!-- /wp:cover -->\n\n<!-- wp:paragraph {\"align\":\"left\"} -->\n<p class=\"has-text-align-left\">Seguici ed indossa anche tu il nostro braccialetto simbolo di Stars For Europe</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:group --></div>\n<!-- /wp:column -->\n\n<!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:group {\"style\":{\"spacing\":{\"blockGap\":\"1.2rem\"}},\"layout\":{\"type\":\"flex\",\"orientation\":\"vertical\",\"justifyContent\":\"stretch\"}} -->\n<div class=\"wp-block-group\"><!-- wp:cover {\"url\":\"http://starsforeurope.local/wp-content/uploads/2025/09/ittadino1-scaled.jpg\",\"id\":62,\"dimRatio\":50,\"style\":{\"color\":[]}} -->\n<div class=\"wp-block-cover\"><img class=\"wp-block-cover__image-background wp-image-62\" alt=\"\" src=\"http://starsforeurope.local/wp-content/uploads/2025/09/ittadino1-scaled.jpg\" data-object-fit=\"cover\"/><span aria-hidden=\"true\" class=\"wp-block-cover__background has-background-dim\"></span><div class=\"wp-block-cover__inner-container\"><!-- wp:paragraph {\"align\":\"center\",\"fontSize\":\"large\"} -->\n<p class=\"has-text-align-center has-large-font-size\">Sei un\'azienda?</p>\n<!-- /wp:paragraph --></div></div>\n<!-- /wp:cover -->\n\n<!-- wp:paragraph {\"align\":\"left\"} -->\n<p class=\"has-text-align-left\">Sostienici con una donazione</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:group --></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns --></div>\n<!-- /wp:group -->\n\n<!-- wp:cover {\"url\":\"http://starsforeurope.local/wp-content/uploads/2025/09/Progetto-senza-titolo-1024x683.jpg\",\"id\":35,\"dimRatio\":70,\"overlayColor\":\"tertiary\",\"isUserOverlayColor\":true,\"minHeight\":590,\"minHeightUnit\":\"px\",\"sizeSlug\":\"large\",\"style\":{\"spacing\":{\"padding\":{\"top\":\"0px\",\"right\":\"4vw\",\"bottom\":\"0px\",\"left\":\"4vw\"},\"margin\":{\"top\":\"0px\",\"bottom\":\"0px\"}},\"color\":{\"duotone\":\"unset\"}},\"textColor\":\"contrast\",\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-cover has-contrast-color has-text-color\" style=\"margin-top:0px;margin-bottom:0px;padding-top:0px;padding-right:4vw;padding-bo