!-- wp:heading {\"textAlign\":\"left\",\"style\":{\"elements\":{\"link\":{\"color\":{\"text\":\"var:preset|color|white\"}}}},\"textColor\":\"white\",\"fontSize\":\"large\"} -->\n<h2 class=\"wp-block-heading has-text-align-left has-white-color has-text-color has-link-color has-large-font-size\">\n  Scrivici per essere aggiornato o per chiederci informazioni: \n  <a href=\"mailto:info@starsforeurope.eu?subject=Richiesta%20informazioni%20Stars%20for%20Europe&amp;body=Ciao%20Stars%20for%20Europe,%0D%0Avorrei%20ricevere%20maggiori%20informazioni%20su...\">info@starsforeurope.eu</a>\n</h2>\n<!-- /wp:heading --></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns --></div>\n<!-- /wp:group -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator --></main>\n<!-- /wp:group -->\n\n<!-- wp:template-part {\"slug\":\"footer\",\"theme\":\"startorg\",\"tagName\":\"footer\",\"area\":\"footer\"} /--></div>\n<!-- /wp:group -->','Home del blog','Visualizza gli ultimi articoli come homepage del sito o come \"Pagina degli articoli\", come definito nelle impostazioni di lettura. Se esiste, il template Pagina principale sovrascrive questo template quando gli articoli vengono visualizzati nella homepage.','inherit','closed','closed','','23-revision-v1','','','2026-03-08 17:33:20','2026-03-08 17:33:20','',23,'http://starsforeurope.local/?p=107',0,'revision','',0);
